            while(!st.empty() && arr[st.top()] <= currEle){
                st.pop();
            }

            // Update the answer
            ans[i] = !st.empty() ? st.top() : n;

            /* Push the index of current 
            element in the stack */
            st.push(i);
        }

        // Return the answer
        return ans;
    }

